// Static content for the DonkeySkills showcase: the skills rail, the document
// samples each animated stage fills in, the slide deck, the clip, and the real
// Form 1120 page plus its auto-extracted field positions (PDF_* below).

export type SkillKind = "pdf" | "doc" | "deck" | "video";
export type Skill = { kind: SkillKind; name: string; promise: string };

export type DocType = "sheet" | "word" | "pdf";

export type DeckSlide = { label: string };

// One field on the form: left/top/width/height as percentages of the page,
// the value to drop in, alignment ("l"eft or "r"ight), and its label.
export type PdfField = {
  l: number;
  t: number;
  w: number;
  h: number;
  v: string;
  a: "l" | "r";
  lab: string;
};

